// Minimal offline stub for SignalR to prevent MIME/404 errors when CDN unavailable.
// Provides no-op implementations sufficient to avoid runtime exceptions in client scripts.
(function(){
  if (window.signalR) return;
  function noop(){ return this; }
  function HubConnection(){ }
  HubConnection.prototype.start = function(){ return Promise.resolve(); };
  HubConnection.prototype.stop = function(){ return Promise.resolve(); };
  HubConnection.prototype.on = noop;
  HubConnection.prototype.off = noop;
  HubConnection.prototype.invoke = function(){ return Promise.resolve(); };
  HubConnection.prototype.send = function(){ return Promise.resolve(); };
  function HubConnectionBuilder(){ this._url=null; }
  HubConnectionBuilder.prototype.withUrl = function(u){ this._url=u; return this; };
  HubConnectionBuilder.prototype.withAutomaticReconnect = function(){ return this; };
  HubConnectionBuilder.prototype.build = function(){ return new HubConnection(); };
  window.signalR = { HubConnectionBuilder: HubConnectionBuilder, LogLevel: { None:0, Error:1, Warning:2, Information:3, Trace:4 } };
})();
